#!/usr/bin/env python3
"""Parse MKGP2 AILapBonusRule table hex dumps from Ghidra read_memory."""
import struct


def parse_table(hex_str, name):
    data = bytes.fromhex(hex_str)
    rules = []
    for i in range(0, len(data), 0x14):
        chunk = data[i:i + 0x14]
        if len(chunk) < 0x14:
            break
        cc = struct.unpack(">b", chunk[0:1])[0]
        sub = struct.unpack(">b", chunk[1:2])[0]
        kart = struct.unpack(">b", chunk[2:3])[0]
        pos = struct.unpack(">b", chunk[3:4])[0]
        lap_min = struct.unpack(">i", chunk[4:8])[0]
        lap_max = struct.unpack(">i", chunk[8:12])[0]
        excl = struct.unpack(">b", chunk[12:13])[0]
        bonus_hex = struct.unpack(">I", chunk[16:20])[0]
        bonus = struct.unpack(">f", chunk[16:20])[0]
        rules.append((cc, sub, kart, pos, lap_min, lap_max, excl, bonus, bonus_hex))
        if cc == -100:
            break
    print(f"### {name}  ({len(rules)} entries incl. sentinel)")
    print("| #  | cc | sub | kart | pos | lapMin | lapMax | excl | bonus     | hex      |")
    print("|----|----|-----|------|-----|--------|--------|------|-----------|----------|")
    for i, r in enumerate(rules):
        cc, sub, kart, pos, lmn, lmx, excl, bn, bh = r
        if cc == -100:
            print(f"| {i:>2} | -- | --  | --   | --  | --     | --     | --   | sentinel  | 9c9c9c9c |")
        else:
            print(f"| {i:>2} | {cc:>2} | {sub:>3} | {kart:>4} | {pos:>3} | {lmn:>6} | {lmx:>6} | {excl:>4} | {bn:+9.2f} | {bh:08x} |")
    print()


TABLES = [
    # Course-table (variant 0). All 8 cups identical.
    (
        "Course-specific table (variant 0) -- IDENTICAL for cup 1..8",
        "02ffff010000000000000032ff000000427000009c9c9c9cffffff9cffffff9c9c00000000000000",
    ),
    (
        "Fallback Mario (cup=1) round=0 variant=0 @ 0x803a3030",
        "",
    ),
    (
        "Fallback Mario (cup=1) round=1 variant=0 @ 0x803a32d8",
        "",
    ),
    (
        "Fallback Mario (cup=1) round=2 variant=0 @ 0x803a34e0",
        "",
    ),
    (
        "Fallback Mario (cup=1) round=3 variant=0 @ 0x803a37b0",
        "",
    ),
    (
        "Fallback Mario (cup=1) round=4 variant=0 @ 0x803a39e0",
        "",
    ),
    (
        "Fallback DK (cup=2) round=0 variant=0 @ 0x803a6424",
        "",
    ),
    (
        "Fallback Rainbow (cup=6) round=0 variant=0 @ 0x803b021c",
        "",
    ),
]


def main():
    for name, hexstr in TABLES:
        parse_table(hexstr, name)


if __name__ == "__main__":
    main()
